module RefModule(
    input clk,
    input reset,
    input d,
    output reg q,
    output reg q_n
);always @(posedge clk or negedge reset) begin
        if (~reset) begin
            q <= 1'b0;
        end else begin
            q <= d;
        end
    end

    wire __q_n_tmp = ~q;
    assign q_n = __q_n_tmp;

endmodule
